#!/usr/bin/env python3
"""Render the prompt-injection accuracy sticky PR comment."""

from __future__ import annotations

import json
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import Any


MARKER = "<!-- risk-accuracy-metrics -->"


@dataclass(frozen=True)
class Mode:
    name: str
    skipped: bool
    skip_reason: str
    total: int
    counts: dict[str, int]
    overall: dict[str, float]
    by_source: list[dict[str, Any]]
    new_false_positives: list[dict[str, Any]]
    recovered_true_positives: list[dict[str, Any]]


def main() -> int:
    if len(sys.argv) < 2 or not Path(sys.argv[1]).is_file():
        print(f"usage: {Path(sys.argv[0]).name} <pr.json> [main.json]", file=sys.stderr)
        return 2

    pr = load_json(Path(sys.argv[1]))
    baseline = load_json(Path(sys.argv[2])) if len(sys.argv) > 2 and Path(sys.argv[2]).is_file() else None
    print(render(pr, baseline))
    return 0


def load_json(path: Path) -> dict[str, Any]:
    with path.open("r", encoding="utf-8") as fh:
        return json.load(fh)


def render(pr: dict[str, Any], baseline: dict[str, Any] | None) -> str:
    summary = pr["summary"]
    counts = summary["counts"]
    malicious = counts["tp"] + counts["fn"]
    benign = counts["fp"] + counts["tn"]

    lines = [
        MARKER,
        "",
        "### Prompt-injection risk report",
        "",
    ]

    corpus = f"Corpus: {summary['total']} cases ({malicious} malicious / {benign} benign)"
    if baseline is not None:
        corpus_delta = summary["total"] - int(baseline["summary"]["total"])
        if corpus_delta:
            corpus += f", {corpus_delta:+d} vs main"
    lines.append(corpus)

    pr_sha = short_sha(str(pr.get("git_sha", "")))
    pr_ts = pr.get("timestamp", "-")
    if baseline is not None:
        lines.append(f"Baseline: `{short_sha(str(baseline.get('git_sha', '')))}` (main) · This PR: `{pr_sha}` · {pr_ts}")
    else:
        lines.append(f"This PR: `{pr_sha}` · {pr_ts}")
    lines.append("")

    lines.extend(render_main_delta(pr, baseline))
    modes = modes_from(summary)
    if modes:
        lines.extend(render_modes(modes))
        l0 = mode_by_name(modes, "l0_default")
        l1 = mode_by_name(modes, "l1_opt_in")
        if l1 is None or l1.skipped:
            reason = l1.skip_reason if l1 is not None else "not present"
            lines.extend([f"L1 opt-in was not evaluated in this run: {reason}.", ""])
        elif l0 is not None and not l0.skipped:
            lines.extend(render_l1_delta(l0, l1))
            lines.extend(render_source_delta("False-Positive Regressions By Source", l0, l1, "fp"))
            lines.extend(render_source_delta("Recall Gains By Source", l0, l1, "tp"))
            lines.append(
                f"Samples in artifact: {len(l1.new_false_positives)} new false positives, "
                f"{len(l1.recovered_true_positives)} recovered true positives."
            )
            lines.append("")
    else:
        lines.extend(render_legacy_l0(summary))

    lines.append(
        "<sub>Generated by <code>.github/scripts/risk-metrics-comment.py</code>. "
        "Full source/rule breakdown and samples are in the <code>risk-accuracy-metrics</code> artifact.</sub>"
    )
    return "\n".join(lines)


def render_main_delta(pr: dict[str, Any], baseline: dict[str, Any] | None) -> list[str]:
    if baseline is None:
        return ["_No main baseline artifact found yet; this comment shows the current run only._", ""]

    pr_mode = primary_mode(pr["summary"])
    base_mode = primary_mode(baseline["summary"])
    deltas = {
        "tp": pr_mode.counts.get("tp", 0) - base_mode.counts.get("tp", 0),
        "fp": pr_mode.counts.get("fp", 0) - base_mode.counts.get("fp", 0),
        "recall": pr_mode.overall.get("recall", 0.0) - base_mode.overall.get("recall", 0.0),
        "f1": pr_mode.overall.get("f1", 0.0) - base_mode.overall.get("f1", 0.0),
        "fp_rate": pr_mode.overall.get("fp_rate", 0.0) - base_mode.overall.get("fp_rate", 0.0),
    }
    if not any(deltas.values()):
        return ["Change vs main: none for the primary operational mode.", ""]

    mode_label = display_mode_name(pr_mode.name)
    base_mode_label = display_mode_name(base_mode.name)
    if pr_mode.name != base_mode.name:
        mode_label = f"PR {mode_label} vs main {base_mode_label}"

    return [
        (
            f"Change vs main ({mode_label}): "
            f"TP {signed_int(deltas['tp'])} · FP {signed_int(deltas['fp'])} · "
            f"recall {signed_pp(deltas['recall'])} · F1 {signed_pp(deltas['f1'])} · "
            f"FP-rate {signed_pp(deltas['fp_rate'])}"
        ),
        "",
    ]


def render_modes(modes: list[Mode]) -> list[str]:
    lines = [
        "**Operational Modes**",
        "",
        "| mode | status | total | TP | FP | FN | precision | recall | F1 | FP-rate |",
        "| --- | --- | ---: | ---: | ---: | ---: | ---: | ---: | ---: | ---: |",
    ]
    for mode in modes:
        if mode.skipped:
            lines.append(f"| {display_mode_name(mode.name)} | skipped | - | - | - | - | - | - | - | - |")
            continue

        lines.append(
            f"| {display_mode_name(mode.name)} | ok | {mode.total} | "
            f"{mode.counts['tp']} | {mode.counts['fp']} | {mode.counts['fn']} | "
            f"{fmt(mode.overall['precision'])} | {fmt(mode.overall['recall'])} | "
            f"{fmt(mode.overall['f1'])} | {fmt(mode.overall['fp_rate'])} |"
        )
    lines.append("")
    return lines


def render_l1_delta(l0: Mode, l1: Mode) -> list[str]:
    return [
        "**Net L1 Opt-In Delta vs L0**",
        "",
        (
            f"TP {signed_int(l1.counts['tp'] - l0.counts['tp'])} · "
            f"FN {signed_int(l1.counts['fn'] - l0.counts['fn'])} · "
            f"FP {signed_int(l1.counts['fp'] - l0.counts['fp'])} · "
            f"recall {signed_pp(l1.overall['recall'] - l0.overall['recall'])} · "
            f"F1 {signed_pp(l1.overall['f1'] - l0.overall['f1'])} · "
            f"FP-rate {signed_pp(l1.overall['fp_rate'] - l0.overall['fp_rate'])}"
        ),
        "",
    ]


def render_source_delta(title: str, l0: Mode, l1: Mode, field: str) -> list[str]:
    baseline = source_counts(l0)
    candidate = source_counts(l1)
    rows = []
    for source in sorted(set(baseline) | set(candidate)):
        before = baseline.get(source, {}).get(field, 0)
        after = candidate.get(source, {}).get(field, 0)
        delta = after - before
        if delta > 0:
            rows.append((source, before, after, delta))

    if not rows:
        return []

    rows.sort(key=lambda row: (-row[3], row[0]))
    lines = [
        f"**{title}**",
        "",
        f"| source | L0 {field.upper()} | L0+L1 {field.upper()} | delta |",
        "| --- | ---: | ---: | ---: |",
    ]
    for source, before, after, delta in rows[:5]:
        lines.append(f"| `{source}` | {before} | {after} | {signed_int(delta)} |")
    lines.append("")
    return lines


def render_legacy_l0(summary: dict[str, Any]) -> list[str]:
    counts = summary["counts"]
    overall = summary["overall"]
    return [
        "**L0 Only**",
        "",
        (
            f"TP {counts['tp']} · FP {counts['fp']} · FN {counts['fn']} · "
            f"precision {fmt(overall['precision'])} · recall {fmt(overall['recall'])} · "
            f"F1 {fmt(overall['f1'])} · FP-rate {fmt(overall['fp_rate'])}"
        ),
        "",
    ]


def modes_from(summary: dict[str, Any]) -> list[Mode]:
    return [
        Mode(
            name=str(item["name"]),
            skipped=bool(item.get("skipped", False)),
            skip_reason=str(item.get("skip_reason", "")),
            total=int(item.get("total", 0)),
            counts={k: int(v) for k, v in item.get("counts", {}).items()},
            overall={k: float(v) for k, v in item.get("overall", {}).items()},
            by_source=list(item.get("by_source", [])),
            new_false_positives=list(item.get("new_false_positives", [])),
            recovered_true_positives=list(item.get("recovered_true_positives", [])),
        )
        for item in summary.get("modes", [])
    ]


def primary_mode(summary: dict[str, Any]) -> Mode:
    modes = modes_from(summary)
    return (
        mode_by_name(modes, "l1_opt_in", require_active=True)
        or mode_by_name(modes, "l0_default", require_active=True)
        or Mode(
            name="l0_default",
            skipped=False,
            skip_reason="",
            total=int(summary["total"]),
            counts={k: int(v) for k, v in summary["counts"].items()},
            overall={k: float(v) for k, v in summary["overall"].items()},
            by_source=list(summary.get("by_source", [])),
            new_false_positives=[],
            recovered_true_positives=[],
        )
    )


def mode_by_name(modes: list[Mode], name: str, require_active: bool = False) -> Mode | None:
    for mode in modes:
        if mode.name == name and (not require_active or not mode.skipped):
            return mode
    return None


def source_counts(mode: Mode) -> dict[str, dict[str, int]]:
    return {item["source"]: item["counts"] for item in mode.by_source}


def display_mode_name(name: str) -> str:
    if name == "l0_default":
        return "L0 only"
    if name == "l1_opt_in":
        return "L0 + L1 opt-in"
    return name


def short_sha(value: str) -> str:
    return value[:8] if value else "-"


def fmt(value: float) -> str:
    return f"{value:.4f}".rstrip("0").rstrip(".")


def signed_int(value: int) -> str:
    return f"{value:+d}"


def signed_pp(value: float) -> str:
    return f"{value * 100:+.1f}pp"


if __name__ == "__main__":
    raise SystemExit(main())
